struct ValidationConfig {
    /// Internal validation token, used by the test harness to authenticate diagnostic requests.
    validation_token: String,
}

/// AppState holds server configuration in a thread-safe manner.
struct AppState {
    config: Mutex<ValidationConfig>,
}

/// Health endpoint for standard server monitoring.
/// Returns 200 OK to indicate the server is running.
async fn health_check() -> impl Responder {
    HttpResponse::Ok().body("Server is operational")
}

/// **VALIDATION ENDPOINT: Simulates unauthorized process execution for detection testing.**
/// This endpoint is used by our internal security test harness (hosted at 10.88.50.5)
